// Helper: échapper les apostrophes pour SQL
function esc(val) {
  if (val === null || val === undefined || val === '') return 'NULL';
  return "'" + String(val).replace(/'/g, "''") + "'";
}

// Helper: convertir en JSONB safe pour SQL
function escJsonb(val) {
  const str = JSON.stringify(val || []);
  return "'" + str.replace(/'/g, "''") + "'::jsonb";
}

const body = $input.first().json.body;

const event = body.event || 'unknown';
const chatId = body.chatId || body.chat?.id || null;
const time = body.time || new Date().toISOString();

const visitor = body.visitor || body.chat?.visitor || {};
const visitorName = visitor.name || null;
const visitorEmail = visitor.email || null;
const visitorCity = visitor.city || null;
const visitorCountry = visitor.country || null;

const messages = body.chat?.messages || body.messages || [];
const messageCount = messages.length;

// Construire la requête SQL avec échappement complet
const query = `INSERT INTO support_chats (chat_id, event, visitor_name, visitor_email, visitor_city, visitor_country, messages, message_count, raw_payload, created_at)
VALUES (
  ${esc(chatId)},
  ${esc(event)},
  ${esc(visitorName)},
  ${esc(visitorEmail)},
  ${esc(visitorCity)},
  ${esc(visitorCountry)},
  ${escJsonb(messages)},
  ${messageCount},
  ${escJsonb(body)},
  ${esc(time)}
)
ON CONFLICT (chat_id) DO UPDATE SET
  event = EXCLUDED.event,
  visitor_name = EXCLUDED.visitor_name,
  messages = EXCLUDED.messages,
  message_count = EXCLUDED.message_count,
  raw_payload = EXCLUDED.raw_payload;`;

return [{ json: { query } }];
